1	#!/usr/bin/env bun
2	/**
3	 * morning.ts — Session briefing for Freddie (/morning)
4	 *
5	 * Displays: greeting → tasks (open + in-progress) → last session → suggestions → knowledge summary.
6	 * Tasks come from tasks.ts CLI for consistent formatting.
7	 *
8	 * Design: fast (<500ms target), read-only, no file mutations.
9	 */
10	
11	import { readFileSync, readdirSync, existsSync } from "fs";
12	import { join, basename } from "path";
13	import { execSync } from "child_process";
14	import { fromRoot } from "../libs/paths.js";
15	import { today, now } from "../libs/dates.js";
16	
17	// ── Paths ─────────────────────────────────────────────────────────────────
18	
19	const SOUL_PATH = fromRoot(".claude", "souls", "freddie.md");
20	const MEMORY_DIR = fromRoot("vault", "studio", "memory");
21	const AUTO_MEMORY_DIR = join(
22	  process.env.HOME || process.env.USERPROFILE || "",
23	  ".claude-personal",
24	  "projects",
25	  "d--PROJECTS-freddie-ai",
26	  "memory"
27	);
28	
29	// ── Greetings ─────────────────────────────────────────────────────────────
30	
31	const GREETINGS = {
32	  morning: [
33	    "Good morning, sir! The studio is warmed up and ready.",
34	    "Morning, sir. Fresh day, fresh context. Shall we begin?",
35	    "Good morning. I've laid out the briefing — coffee's on you.",
36	    "Rise and shine, sir. The agents are standing by.",
37	  ],
38	  afternoon: [
39	    "Good afternoon, sir. What are we building today?",
40	    "Afternoon, sir. The board is set. Your move.",
41	    "Good afternoon. I've reviewed the state of things — here's where we are.",
42	    "Afternoon, sir. Let's pick up where we left off.",
43	  ],
44	  evening: [
45	    "Good evening, sir. Ready for your shift?",
46	    "Evening, sir. The night shift has its advantages — fewer interruptions.",
47	    "Good evening. I've prepared your briefing. The vault is quiet.",
48	    "Evening, sir. Let's make the most of the quiet hours.",
49	  ],
50	};
51	
52	function getGreeting(hour: number): string {
53	  let pool: string[];
54	  if (hour >= 5 && hour < 12) pool = GREETINGS.morning;
55	  else if (hour >= 12 && hour < 18) pool = GREETINGS.afternoon;
56	  else pool = GREETINGS.evening;
57	  return pool[Math.floor(Math.random() * pool.length)];
58	}
59	
60	// ── Soul loader ───────────────────────────────────────────────────────────
61	
62	function loadSoulSummary(): string | null {
63	  if (!existsSync(SOUL_PATH)) return null;
64	  const content = readFileSync(SOUL_PATH, "utf-8");
65	  const title = content.split("\n").find((l) => l.startsWith("# "));
66	  return title?.replace(/^#\s*/, "") || null;
67	}
68	
69	// ── Knowledge scanner ─────────────────────────────────────────────────────
70	
71	interface AgentMemoryStatus {
72	  agent: string;
73	  inboxCount: number;
74	  knowledgeCount: number;
75	}
76	
77	function scanAgentMemory(): AgentMemoryStatus[] {
78	  if (!existsSync(MEMORY_DIR)) return [];
79	  const agents = readdirSync(MEMORY_DIR, { withFileTypes: true })
80	    .filter((d) => d.isDirectory())
81	    .map((d) => d.name);
82	
83	  return agents
84	    .map((agent) => {
85	      const inboxDir = join(MEMORY_DIR, agent, "inbox");
86	      const knowledgeDir = join(MEMORY_DIR, agent, "knowledge");
87	      const inboxCount = existsSync(inboxDir)
88	        ? readdirSync(inboxDir).filter((f) => f.endsWith(".md")).length
89	        : 0;
90	      const knowledgeCount = existsSync(knowledgeDir)
91	        ? readdirSync(knowledgeDir).filter((f) => f.endsWith(".md")).length
92	        : 0;
93	      return { agent, inboxCount, knowledgeCount };
94	    })
95	    .filter((a) => a.inboxCount > 0 || a.knowledgeCount > 0);
96	}
97	
98	// ── Task loader via tasks.ts CLI ──────────────────────────────────────────
99	
100	interface TaskDisplay {
101	  lines: string[];
102	  openCount: number;
103	  inProgressCount: number;
104	  doneCount: number;
105	}
106	
107	function loadTasks(date: string): TaskDisplay {
108	  const tasksScript = fromRoot("src", "tools", "obsidian", "tasks.ts");
109	  const result: TaskDisplay = { lines: [], openCount: 0, inProgressCount: 0, doneCount: 0 };
110	
111	  try {
112	    // Get summary for counts
113	    const summaryOutput = execSync(`bun "${tasksScript}" summary --date ${date}`, {
114	      encoding: "utf-8",
115	      timeout: 5000,
116	    }).trim();
117	
118	    // Parse counts from summary line: "2026-03-31: 12/24 tasks — 12 [x] done, 10 [>] deferred, ..."
119	    const doneMatch = summaryOutput.match(/(\d+) \[x\] done/);
120	    if (doneMatch) result.doneCount = parseInt(doneMatch[1], 10);
121	
122	    // Get todo tasks ([ ] only — excludes in-progress, urgent, question)
123	    const openOutput = execSync(`bun "${tasksScript}" list --date ${date} --filter todo`, {
124	      encoding: "utf-8",
125	      timeout: 5000,
126	    }).trim();
127	
128	    // Get in-progress tasks ([/] only)
129	    const inProgressOutput = execSync(`bun "${tasksScript}" list --date ${date} --filter in_progress`, {
130	      encoding: "utf-8",
131	      timeout: 5000,
132	    }).trim();
133	
134	    // Parse task lines (skip the summary header line)
135	    const parseTaskLines = (output: string, status: "open" | "in_progress"): string[] => {
136	      const lines = output.split("\n");
137	      const taskLines: string[] = [];
138	      for (const line of lines) {
139	        // Skip header/summary lines
140	        if (line.startsWith("No tasks") || line.match(/^\d{4}-\d{2}-\d{2}:/)) continue;
141	        if (!line.trim()) continue;
142	
143	        // Match task lines: [ ] [1] or [/] [2] or indented subtasks
144	        const topTask = line.match(/^\[[ /x>~-]\]\s+\[(\d+)\]\s+(.+)/);
145	        const subTask = line.match(/^\s+\[[ /x>~-]\]\s+\[(\d+\.\d+)\]\s+(.+)/);
146	
147	        if (topTask) {
148	          const marker = status === "in_progress" ? "[/]" : "[ ]";
149	          taskLines.push(`${marker} [${topTask[1]}] - ${topTask[2]}`);
150	        } else if (subTask) {
151	          const marker = status === "in_progress" ? "[/]" : "[ ]";
152	          taskLines.push(`    ${marker} [${subTask[1]}] ${subTask[2]}`);
153	        }
154	      }
155	      return taskLines;
156	    };
157	
158	    const openLines = parseTaskLines(openOutput, "open");
159	    const ipLines = parseTaskLines(inProgressOutput, "in_progress");
160	
161	    result.openCount = openLines.filter((l) => !l.startsWith("    ")).length;
162	    result.inProgressCount = ipLines.filter((l) => !l.startsWith("    ")).length;
163	    result.lines = [...openLines, ...ipLines];
164	  } catch {
165	    // tasks.ts failed — non-blocking
166	  }
167	
168	  return result;
169	}
170	
171	// ── Last session finder ───────────────────────────────────────────────────
172	
173	interface SessionInfo {
174	  date: string;
175	  summary: string;
176	}
177	
178	function findLastSession(): SessionInfo | null {
179	  if (!existsSync(AUTO_MEMORY_DIR)) return null;
180	
181	  const sessionFiles = readdirSync(AUTO_MEMORY_DIR)
182	    .filter((f) => f.startsWith("project_session_") && f.endsWith(".md"))
183	    .sort()
184	    .reverse();
185	
186	  if (sessionFiles.length === 0) return null;
187	
188	  const latest = sessionFiles[0];
189	  const content = readFileSync(join(AUTO_MEMORY_DIR, latest), "utf-8");
190	
191	  const dateMatch = latest.match(/project_session_(\d{4})(\d{2})(\d{2})/);
192	  const date = dateMatch ? `${dateMatch[1]}-${dateMatch[2]}-${dateMatch[3]}` : "unknown";
193	
194	  const descMatch = content.match(/^description:\s*(.+)$/m);
195	  const summary =
196	    descMatch?.[1] ||
197	    content
198	      .split("\n")
199	      .find(
200	        (l) =>
201	          l.length > 10 &&
202	          !l.startsWith("---") &&
203	          !l.startsWith("name:") &&
204	          !l.startsWith("type:")
205	      )
206	      ?.trim() ||
207	    "No summary available";
208	
209	  return { date, summary: summary.length > 120 ? summary.slice(0, 117) + "..." : summary };
210	}
211	
212	// ── Suggestions ───────────────────────────────────────────────────────────
213	
214	function buildSuggestions(
215	  agentStatuses: AgentMemoryStatus[],
216	  taskDisplay: TaskDisplay
217	): string[] {
218	  const suggestions: string[] = [];
219	
220	  const needsConsolidation = agentStatuses.filter((a) => a.inboxCount >= 3);
221	  for (const a of needsConsolidation) {
222	    suggestions.push(
223	      `${capitalize(a.agent)} has ${a.inboxCount} inbox items — consolidation ready`
224	    );
225	  }
226	
227	  const hasInbox = agentStatuses.filter((a) => a.inboxCount > 0 && a.inboxCount < 3);
228	  if (hasInbox.length > 0) {
229	    const names = hasInbox
230	      .map((a) => `${capitalize(a.agent)} (${a.inboxCount})`)
231	      .join(", ");
232	    suggestions.push(`Inbox items: ${names}`);
233	  }
234	
235	  if (taskDisplay.openCount > 5) {
236	    suggestions.push(
237	      `${taskDisplay.openCount} open tasks — consider triaging or deferring some`
238	    );
239	  }
240	
241	  return suggestions;
242	}
243	
244	function capitalize(s: string): string {
245	  return s.charAt(0).toUpperCase() + s.slice(1);
246	}
247	
248	// ── Main ──────────────────────────────────────────────────────────────────
249	
250	function main() {
251	  const { date, time } = now();
252	  const hour = parseInt(time.slice(0, 2), 10);
253	  const greeting = getGreeting(hour);
254	  const soul = loadSoulSummary();
255	  const agentStatuses = scanAgentMemory();
256	  const taskDisplay = loadTasks(date);
257	  const lastSession = findLastSession();
258	  const suggestions = buildSuggestions(agentStatuses, taskDisplay);
259	
260	  const lines: string[] = [];
261	
262	  // Identity + greeting
263	  if (soul) lines.push(`[${soul}]`);
264	  lines.push("");
265	  lines.push(greeting);
266	  lines.push("");
267	
268	  // Tasks
269	  lines.push("━━ Briefing ━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━");
270	  lines.push("");
271	
272	  if (taskDisplay.lines.length > 0) {
273	    lines.push("Tasks:");
274	    for (const line of taskDisplay.lines) {
275	      lines.push(`  ${line}`);
276	    }
277	    lines.push("");
278	    lines.push(
279	      `  Summary: ${taskDisplay.openCount} Open | ${taskDisplay.inProgressCount} In-Progress | ${taskDisplay.doneCount} Done`
280	    );
281	    lines.push("");
282	  } else {
283	    lines.push("Tasks: No open or in-progress tasks.");
284	    lines.push("");
285	  }
286	
287	  // Last session
288	  if (lastSession) {
289	    lines.push(`Last session (${lastSession.date}):`);
290	    lines.push(`  ${lastSession.summary}`);
291	    lines.push("");
292	  }
293	
294	  // Suggestions
295	  if (suggestions.length > 0) {
296	    lines.push("Suggested:");
297	    for (const s of suggestions) {
298	      lines.push(`  > ${s}`);
299	    }
300	    lines.push("");
301	  }
302	
303	  // Agent knowledge summary (compact)
304	  const withKnowledge = agentStatuses.filter((a) => a.knowledgeCount > 0);
305	  if (withKnowledge.length > 0) {
306	    const summary = withKnowledge
307	      .map((a) => `${capitalize(a.agent)}(${a.knowledgeCount})`)
308	      .join(" ");
309	    lines.push(`Knowledge loaded: ${summary}`);
310	    lines.push("");
311	  }
312	
313	  lines.push("━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━");
314	
315	  process.stdout.write(lines.join("\n"));
316	}
317	
318	try {
319	  main();
320	} catch (err) {
321	  process.stderr.write(
322	    `[init] Error: ${err instanceof Error ? err.message : String(err)}\n`
323	  );
324	}
325	
326	process.exit(0);
