  morning: [
    "Good morning, sir! The studio is warmed up and ready.",
    "Morning, sir. Fresh day, fresh context. Shall we begin?",
    "Good morning. I've laid out the briefing — coffee's on you.",
    "Rise and shine, sir. The agents are standing by.",
  ],
  afternoon: [
    "Good afternoon, sir. What are we building today?",
    "Afternoon, sir. The board is set. Your move.",
    "Good afternoon. I've reviewed the state of things — here's where we are.",
    "Afternoon, sir. Let's pick up where we left off.",
  ],
  evening: [
    "Good evening, sir. Ready for your shift?",
    "Evening, sir. The night shift has its advantages — fewer interruptions.",
    "Good evening. I've prepared your briefing. The vault is quiet.",
    "Evening, sir. Let's make the most of the quiet hours.",
  ],
};

function getGreeting(hour: number): string {
  let pool: string[];
  if (hour >= 5 && hour < 12) pool = GREETINGS.morning;
  else if (hour >= 12 && hour < 18) pool = GREETINGS.afternoon;
  else pool = GREETINGS.evening;
  return pool[Math.floor(Math.random() * pool.length)];
}

// ── Soul loader ───────────────────────────────────────────────────────────

function loadSoulSummary(): string | null {
  if (!existsSync(SOUL_PATH)) return null;
  const content = readFileSync(SOUL_PATH, "utf-8");
  const title = content.split("\n").find((l) => l.startsWith("# "));
  return title?.replace(/^#\s*/, "") || null;
}

// ── Knowledge scanner ─────────────────────────────────────────────────────

interface AgentMemoryStatus {
  agent: string;
  inboxCount: number;
  knowledgeCount: number;
}

function scanAgentMemory(): AgentMemoryStatus[] {
  if (!existsSync(MEMORY_DIR)) return [];
  const agents = readdirSync(MEMORY_DIR, { withFileTypes: true })
    .filter((d) => d.isDirectory())
    .map((d) => d.name);

  return agents
    .map((agent) => {
      const inboxDir = join(MEMORY_DIR, agent, "inbox");
      const knowledgeDir = join(MEMORY_DIR, agent, "knowledge");
      const inboxCount = existsSync(inboxDir)
        ? readdirSync(inboxDir).filter((f) => f.endsWith(".md")).length
        : 0;
      const knowledgeCount = existsSync(knowledgeDir)
        ? readdirSync(knowledgeDir).filter((f) => f.endsWith(".md")).length
        : 0;
      return { agent, inboxCount, knowledgeCount };
    })
    .filter((a) => a.inboxCount > 0 || a.knowledgeCount > 0);
}

// ── Task loader via tasks.ts CLI ──────────────────────────────────────────

interface TaskDisplay {
  lines: string[];
  openCount: number;
  inProgressCount: number;
  doneCount: number;
}

function loadTasks(date: string): TaskDisplay {
  const tasksScript = fromRoot("src", "tools", "obsidian", "tasks.ts");
  const result: TaskDisplay = { lines: [], openCount: 0, inProgressCount: 0, doneCount: 0 };

  try {
    // Get summary for counts
    const summaryOutput = execSync(`bun "${tasksScript}" summary --date ${date}`, {
      encoding: "utf-8",
      timeout: 5000,
    }).trim();

    // Parse counts from summary line: "2026-03-31: 12/24 tasks — 12 [x] done, 10 [>] deferred, ..."
    const doneMatch = summaryOutput.match(/(\d+) \[x\] done/);
    if (doneMatch) result.doneCount = parseInt(doneMatch[1], 10);

    // Get todo tasks ([ ] only — excludes in-progress, urgent, question)
    const openOutput = execSync(`bun "${tasksScript}" list --date ${date} --filter todo`, {
      encoding: "utf-8",
      timeout: 5000,
    }).trim();

    // Get in-progress tasks ([/] only)
    const inProgressOutput = execSync(`bun "${tasksScript}" list --date ${date} --filter in_progress`, {
      encoding: "utf-8",
      timeout: 5000,
    }).trim();

    // Parse task lines (skip the summary header line)
    const parseTaskLines = (output: string, status: "open" | "in_progress"): string[] => {
      const lines = output.split("\n");
      const taskLines: string[] = [];
      for (const line of lines) {
        // Skip header/summary lines
        if (line.startsWith("No tasks") || line.match(/^\d{4}-\d{2}-\d{2}:/)) continue;
        if (!line.trim()) continue;

        // Match task lines: [ ] [1] or [/] [2] or indented subtasks
        const topTask = line.match(/^\[[ /x>~-]\]\s+\[(\d+)\]\s+(.+)/);
        const subTask = line.match(/^\s+\[[ /x>~-]\]\s+\[(\d+\.\d+)\]\s+(.+)/);

        if (topTask) {
          const marker = status === "in_progress" ? "[/]" : "[ ]";
          taskLines.push(`${marker} [${topTask[1]}] - ${topTask[2]}`);
        } else if (subTask) {
          const marker = status === "in_progress" ? "[/]" : "[ ]";
          taskLines.push(`    ${marker} [${subTask[1]}] ${subTask[2]}`);
        }
      }
      return taskLines;
    };

    const openLines = parseTaskLines(openOutput, "open");
    const ipLines = parseTaskLines(inProgressOutput, "in_progress");

    result.openCount = openLines.filter((l) => !l.startsWith("    ")).length;
    result.inProgressCount = ipLines.filter((l) => !l.startsWith("    ")).length;
    result.lines = [...openLines, ...ipLines];
  } catch {
    // tasks.ts failed — non-blocking
  }

  return result;
}

// ── Last session finder ───────────────────────────────────────────────────

interface SessionInfo {
  date: string;
  summary: string;
}

function findLastSession(): SessionInfo | null {
  if (!existsSync(AUTO_MEMORY_DIR)) return null;

  const sessionFiles = readdirSync(AUTO_MEMORY_DIR)
    .filter((f) => f.startsWith("project_session_") && f.endsWith(".md"))
    .sort()
    .reverse();

  if (sessionFiles.length === 0) return null;

  const latest = sessionFiles[0];
  const content = readFileSync(join(AUTO_MEMORY_DIR, latest), "utf-8");

  const dateMatch = latest.match(/project_session_(\d{4})(\d{2})(\d{2})/);
  const date = dateMatch ? `${dateMatch[1]}-${dateMatch[2]}-${dateMatch[3]}` : "unknown";

  const descMatch = content.match(/^description:\s*(.+)$/m);
  const summary =
    descMatch?.[1] ||
    content
      .split("\n")
      .find(
        (l) =>
          l.length > 10 &&
          !l.startsWith("---") &&
          !l.startsWith("name:") &&
          !l.startsWith("type:")
      )
      ?.trim() ||
    "No summary available";

  return { date, summary: summary.length > 120 ? summary.slice(0, 117) + "..." : summary };
}

// ── Suggestions ───────────────────────────────────────────────────────────

function buildSuggestions(
  agentStatuses: AgentMemoryStatus[],
  taskDisplay: TaskDisplay
): string[] {
  const suggestions: string[] = [];

  const needsConsolidation = agentStatuses.filter((a) => a.inboxCount >= 3);
  for (const a of needsConsolidation) {
    suggestions.push(
      `${capitalize(a.agent)} has ${a.inboxCount} inbox items — consolidation ready`
    );
  }

  const hasInbox = agentStatuses.filter((a) => a.inboxCount > 0 && a.inboxCount < 3);
  if (hasInbox.length > 0) {
    const names = hasInbox
      .map((a) => `${capitalize(a.agent)} (${a.inboxCount})`)
      .join(", ");
    suggestions.push(`Inbox items: ${names}`);
  }

  if (taskDisplay.openCount > 5) {
    suggestions.push(
      `${taskDisplay.openCount} open tasks — consider triaging or deferring some`
    );
  }

  return suggestions;
}

function capitalize(s: string): string {
  return s.charAt(0).toUpperCase() + s.slice(1);
}

// ── Main ──────────────────────────────────────────────────────────────────

function main() {
  const { date, time } = now();
  const hour = parseInt(time.slice(0, 2), 10);
  const greeting = getGreeting(hour);
  const soul = loadSoulSummary();
  const agentStatuses = scanAgentMemory();
  const taskDisplay = loadTasks(date);
  const lastSession = findLastSession();
  const suggestions = buildSuggestions(agentStatuses, taskDisplay);

  const lines: string[] = [];

  // Identity + greeting
  if (soul) lines.push(`[${soul}]`);
  lines.push("");
  lines.push(greeting);
  lines.push("");

  // Tasks
  lines.push("━━ Briefing ━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━");
  lines.push("");

  if (taskDisplay.lines.length > 0) {
    lines.push("Tasks:");
    for (const line of taskDisplay.lines) {
      lines.push(`  ${line}`);
    }
    lines.push("");
    lines.push(
      `  Summary: ${taskDisplay.openCount} Open | ${taskDisplay.inProgressCount} In-Progress | ${taskDisplay.doneCount} Done`
    );
    lines.push("");
  } else {
    lines.push("Tasks: No open or in-progress tasks.");
    lines.push("");
  }

  // Last session
  if (lastSession) {
    lines.push(`Last session (${lastSession.date}):`);
    lines.push(`  ${lastSession.summary}`);
    lines.push("");
  }

  // Suggestions
  if (suggestions.length > 0) {
    lines.push("Suggested:");
    for (const s of suggestions) {
      lines.push(`  > ${s}`);
    }
    lines.push("");
  }

  // Agent knowledge summary (compact)
  const withKnowledge = agentStatuses.filter((a) => a.knowledgeCount > 0);
  if (withKnowledge.length > 0) {
    const summary = withKnowledge
      .map((a) => `${capitalize(a.agent)}(${a.knowledgeCount})`)
      .join(" ");
    lines.push(`Knowledge loaded: ${summary}`);
    lines.push("");
  }

  lines.push("━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━");

  process.stdout.write(lines.join("\n"));
}

try {
  main();
} catch (err) {
  process.stderr.write(
    `[init] Error: ${err instanceof Error ? err.message : String(err)}\n`
  );
}

process.exit(0);

