#!/usr/bin/env bun
/**
 * startup.ts — Session context loader
 *
 * SessionStart hook: loads all agent souls + Freddie's knowledge files
 * into session context via stdout. Other agent knowledge loads on-demand
 * when agents are dispatched.
 *
 * Budget: ~62KB (38KB souls + 24KB Freddie knowledge)
 */

import { readFileSync, readdirSync, existsSync } from "fs";
import { join, basename } from "path";
import { fromRoot } from "../../src/libs/paths.js";

const SOULS_DIR = fromRoot(".claude", "souls");
const FREDDIE_KNOWLEDGE_DIR = fromRoot("vault", "studio", "memory", "freddie", "knowledge");
const AUTO_MEMORY_DIR = join(
  process.env.HOME || process.env.USERPROFILE || "",
  ".claude-personal",
  "projects",
  "d--PROJECTS-freddie-ai",
  "memory"
);

// ── Load all soul files ──────────────────────────────────────────────────

function loadSouls(): string[] {
  if (!existsSync(SOULS_DIR)) return [];
  const files = readdirSync(SOULS_DIR)
    .filter((f) => f.endsWith(".md"))
    .sort();

  const sections: string[] = [];
  for (const file of files) {
    const name = basename(file, ".md");
    const content = readFileSync(join(SOULS_DIR, file), "utf-8").trim();
    sections.push(`── ${name} ──\n${content}`);
  }
  return sections;
}

// ── Load Freddie's knowledge ─────────────────────────────────────────────

function loadFreddieKnowledge(): string[] {
  if (!existsSync(FREDDIE_KNOWLEDGE_DIR)) return [];
  const files = readdirSync(FREDDIE_KNOWLEDGE_DIR)
    .filter((f) => f.endsWith(".md"))
    .sort();

  const sections: string[] = [];
  for (const file of files) {
    const name = basename(file, ".md");
    const content = readFileSync(join(FREDDIE_KNOWLEDGE_DIR, file), "utf-8").trim();
    sections.push(`── ${name} ──\n${content}`);
  }
  return sections;
}

// ── Main ─────────────────────────────────────────────────────────────────

function main() {
  const lines: string[] = [];

  const souls = loadSouls();
  if (souls.length > 0) {
    lines.push("═══ AGENT SOULS ═══");
    lines.push(souls.join("\n\n"));
    lines.push("");
  }

  const knowledge = loadFreddieKnowledge();
  if (knowledge.length > 0) {
    lines.push("═══ FREDDIE KNOWLEDGE ═══");
    lines.push(knowledge.join("\n\n"));
    lines.push("");
  }

  if (lines.length > 0) {
    process.stdout.write(lines.join("\n"));
  }
}

try {
  main();
} catch (err) {
  // Never block session start
  process.stderr.write(`[startup] Error: ${err instanceof Error ? err.message : String(err)}\n`);
}

process.exit(0);

